"use client";

import {
  Presence as PresencePrimitive,
  PresenceProvider,
  splitPresenceProps,
  type PresenceProps as PresencePrimitiveProps,
  usePresence,
  usePresenceContext,
} from "@ark-ui/react/presence";
import { cn } from "@/lib/utils";

export type PresenceProps = PresencePrimitiveProps;

export const Presence = ({ className, ...props }: PresenceProps) => (
  <PresencePrimitive
    className={cn(className)}
    data-slot="presence"
    {...props}
  />
);

export { PresenceProvider, splitPresenceProps, usePresence, usePresenceContext };

export type {
  PresenceBaseProps,
  UsePresenceContext,
  UsePresenceProps,
  UsePresenceReturn,
} from "@ark-ui/react/presence";
